#!/usr/bin/env node
import { randomBytes } from "node:crypto"
import { chmodSync, existsSync, readFileSync, writeFileSync } from "node:fs"
import path from "node:path"
import { fileURLToPath } from "node:url"
import { loadContract, parseEnvText } from "./validate-env.mjs"

const scriptPath = fileURLToPath(import.meta.url)
const scriptDir = path.dirname(scriptPath)
const repoRoot = path.resolve(scriptDir, "../..")
const defaultContractPath = path.join(repoRoot, "deploy/env/env.contract.json")

const resolveTarget = (contract, targetName) => {
  const target = contract.targets?.[targetName]
  if (!target) throw new Error(`Unknown render target: ${targetName}`)
  return target
}

const valueOf = (env, key) => env.get(key)?.trim() || ""

const fillTemplate = (template, sourceEnv) =>
  template.replace(/\$\{([A-Za-z_][A-Za-z0-9_]*)\}/g, (_match, key) => valueOf(sourceEnv, key))

const generatedValue = (spec) => {
  if (!spec.generate) return ""
  const match = spec.generate.match(/^hex:(\d+)$/)
  if (!match) throw new Error(`Unsupported generator for ${spec.name}: ${spec.generate}`)
  return randomBytes(Number.parseInt(match[1], 10)).toString("hex")
}

const quoteEnvValue = (value) => {
  const raw = String(value ?? "")
  if (raw === "") return ""
  if (/^[A-Za-z0-9_./:@%+=,\-$[\]]+$/.test(raw)) return raw
  return JSON.stringify(raw)
}

export const renderTargetEnv = ({ contract, target, sourceText = "", existingText = "" }) => {
  const resolved = resolveTarget(contract, target)
  const sourceEnv = parseEnvText(sourceText)
  const existingEnv = parseEnvText(existingText)

  if (!Array.isArray(resolved.render)) {
    throw new Error(`Target does not define render entries: ${target}`)
  }

  const lines = [
    `# Generated by tools/env/render-local-env.mjs --target ${target}.`,
    "# Local secrets are intentionally ignored by git.",
    "",
  ]

  for (const spec of resolved.render) {
    let value = ""

    if (spec.preserve) value = valueOf(existingEnv, spec.name)
    if (!value && Array.isArray(spec.from)) {
      for (const sourceKey of spec.from) {
        value = valueOf(existingEnv, sourceKey) || valueOf(sourceEnv, sourceKey)
        if (value) break
      }
    }
    if (!value && spec.template) value = fillTemplate(spec.template, sourceEnv)
    if (!value && Object.hasOwn(spec, "fallback")) value = spec.fallback
    if (!value && spec.generate) value = generatedValue(spec)

    lines.push(`${spec.name}=${quoteEnvValue(value)}`)
  }

  return `${lines.join("\n")}\n`
}

const parseArgs = (argv) => {
  const args = { contract: defaultContractPath }
  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index]
    if (arg === "--target") args.target = argv[++index]
    else if (arg === "--source") args.source = argv[++index]
    else if (arg === "--out") args.out = argv[++index]
    else if (arg === "--contract") args.contract = argv[++index]
    else throw new Error(`Unknown argument: ${arg}`)
  }
  return args
}

const main = () => {
  const args = parseArgs(process.argv.slice(2))
  if (!args.target) throw new Error("--target is required")
  if (!args.out) throw new Error("--out is required")

  const sourceText = args.source && existsSync(args.source) ? readFileSync(args.source, "utf8") : ""
  const existingText = existsSync(args.out) ? readFileSync(args.out, "utf8") : ""
  const output = renderTargetEnv({
    contract: loadContract(args.contract),
    target: args.target,
    sourceText,
    existingText,
  })

  writeFileSync(args.out, output, { mode: 0o600 })
  chmodSync(args.out, 0o600)
  console.log(`[env-contract] rendered ${args.target} -> ${args.out}`)
}

if (process.argv[1] === scriptPath) {
  try {
    main()
  } catch (error) {
    console.error(`[env-contract] ${error instanceof Error ? error.message : String(error)}`)
    process.exit(1)
  }
}
